"""Stub for fairseq.dataclass.configs.FairseqConfig.

Pickle references this class by name; we provide a tolerant stub that
captures restored state into __dict__ and returns None for missing
attribute accesses. ComfyUI-RVC only reads `saved_cfg.task.normalize`
from the loaded cfg, which works as long as the pickle restored that
attribute path."""


class FairseqConfig:
    def __init__(self, *args, **kwargs):
        pass

    def __setstate__(self, state):
        if isinstance(state, dict):
            self.__dict__.update(state)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __reduce__(self):
        return (self.__class__, ())
